import{_ as a}from"./chunks/ProjectDetails.DJkSSHiL.js";import{_ as t,o,c as r,ae as s}from"./chunks/framework.C00B0EYs.js";const g=JSON.parse('{"title":"Project Details and Save","description":"Review project metadata, statistics, save behavior, and history controls.","frontmatter":{"title":"Project Details and Save","description":"Review project metadata, statistics, save behavior, and history controls."},"headers":[],"relativePath":"docs/guide/project-details-and-save.md","filePath":"docs/guide/project-details-and-save.md"}'),i={name:"docs/guide/project-details-and-save.md"};function n(d,e,c,l,p,h){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="project-details-and-save" tabindex="-1">Project Details and Save <a class="header-anchor" href="#project-details-and-save" aria-label="Permalink to &quot;Project Details and Save&quot;">​</a></h1><p>This page explains what you can see in the project details dialog, what <code>.msep</code> is for, and how save behavior currently works.</p><h2 id="_1-project-details" tabindex="-1">1. Project details <a class="header-anchor" href="#_1-project-details" aria-label="Permalink to &quot;1. Project details&quot;">​</a></h2><p><img src="'+a+'" alt="Project details"></p><p><strong>Project Details</strong> shows the current project name along with a set of project statistics. In the current implementation:</p><ul><li><strong>Editable field</strong>: project name.</li><li><strong>Read-only information</strong>: file path, track count, audio-asset count, assigned-audio count, total keyframes, maximum speed, acceleration, brake deceleration, created time, and updated time.</li></ul><p>These values are useful when you want to confirm the current state of a project before continuing to edit or preparing an export.</p><h2 id="_2-the-msep-project-format" tabindex="-1">2. The <code>.msep</code> project format <a class="header-anchor" href="#_2-the-msep-project-format" aria-label="Permalink to &quot;2. The `.msep` project format&quot;">​</a></h2><p>Motor Sound Editor uses <code>.msep</code> as its native project file format.</p><ul><li><strong>Packaged together</strong>: <code>.msep</code> stores project metadata, track definitions, curve data, and packaged audio resources in one file.</li><li><strong>Portable</strong>: you do not need to manage a separate folder of loose audio files when moving or sharing the project.</li><li><strong>Editable source</strong>: <code>.msep</code> is the editable source project, not the final delivery package.</li></ul><h2 id="_3-save-and-unsaved-changes" tabindex="-1">3. Save and unsaved changes <a class="header-anchor" href="#_3-save-and-unsaved-changes" aria-label="Permalink to &quot;3. Save and unsaved changes&quot;">​</a></h2><ul><li><strong>Unsaved state</strong>: the project becomes dirty when you add tracks, edit keyframes, replace audio, or update the project name.</li><li><strong>Save</strong> writes the current document and packaged audio back to the existing <code>.msep</code> file.</li><li><strong>Save As</strong> writes the current project into a new <code>.msep</code> file.</li><li><strong>Leave confirmation</strong> appears before returning home or closing the window if the project still has unsaved changes.</li><li><strong>Undo / redo</strong> remains available during the current session even after saving, as long as the app stays open.</li></ul>',12)])])}const f=t(i,[["render",n]]);export{g as __pageData,f as default};
